// ╔══════════════════════════════════════════════════════╗
// ║  MODULE 0: CENTRAL CONFIG                            ║
// ║  All settings in one place. Edit only this node.    ║
// ╚══════════════════════════════════════════════════════╝

const CONFIG = {
  // ── User Settings ────────────────────────────────────
  user_email: 'maherahmedraza1@gmail.com',

  // ── Backfill Date Range (YYYY/MM/DD) ─────────────────
  backfill_after:  '2025/10/01',
  backfill_before: '2026/04/06',

  // ── Gemini AI Settings ───────────────────────────────
  // Valid models: gemini-3.1-flash-lite-preview (cheapest)
  //               gemini-3-flash-preview
  //               gemini-3.1-pro-preview (best)
  //               gemini-1.5-flash-8b (stable fallback)
  gemini_model:      'gemini-3.1-flash-lite-preview',
  thinking_level:    'minimal',   // minimal | low | medium | high
  gemini_batch_size: 10,          // emails per Gemini API call
  batch_delay_ms:    2000,        // ms between batches
  min_confidence:    0.55,        // below this = not_job_related

  // ── Telegram Notifications ───────────────────────────
  telegram_enabled:   false,
  telegram_bot_token: '',
  telegram_chat_id:   '',

  // ── Gmail Blocked Senders (exact match) ──────────────
  blocked_senders_exact: [
    'notifications-noreply@linkedin.com',
    'jobs-listings@linkedin.com',
    'jobs-noreply@linkedin.com',
    'jobalerts-noreply@linkedin.com',
    'inmail-hit-reply@linkedin.com',
    'updates-noreply@linkedin.com',
    'messages-noreply@linkedin.com',
    'learning-noreply@linkedin.com',
    'news-noreply@linkedin.com',
    'premium-noreply@linkedin.com',
    'news@mail.xing.com',
    'info@jobagent.stepstone.de',
    'jobalert@indeed.com',
    'alert@indeed.com',
    'noreply@indeed.com',
    'hello@dataquest.io',
    'stefan.huber@hokify.com',
    'noreply@arbeitsagentur.de'
  ],

  // ── Gmail Blocked Sender Patterns (substring match) ───
  sender_block_patterns: [
    'jobalerts-noreply@',
    'jobs-listings@linkedin',
    'notifications-noreply@linkedin',
    'updates-noreply@linkedin',
    'messages-noreply@linkedin',
    'learning-noreply@linkedin',
    'news-noreply@linkedin',
    'premium-noreply@linkedin',
    'jobagent@stepstone',
    'jobagent@indeed',
    '@hokify.com',
    'noreply@newsletter.',
    'jobalert@',
    'job-alert@'
  ],

  // ── University Email Patterns ─────────────────────────
  university_patterns: [
    'uni-koblenz.de', 'list.uni-', 'studierende@', '@asta.'
  ],

  // ── Subject Lines to Always Exclude ──────────────────
  subject_always_exclude: [
    'new jobs for you', 'neue jobs für dich',
    'jobs matching your search', 'jobs you might like',
    'job recommendations', 'new jobs in your area',
    'companies are looking for candidates like you',
    'read this article', 'read on linkedin',
    'published a newsletter', 'published an article',
    'started a new position', 'is celebrating', 'has a new job',
    'people viewed your profile', 'search appearances',
    'your posts got', 'impressions last week',
    'top voices', 'trending on linkedin',
    'weekly digest', 'monthly digest', 'connection digest', 'weekly roundup',
    'career tips', 'karrieretipps',
    'job alert', 'job-alert', 'jobalert',
    'new jobs matching', 'jobs matching your',
    '10+ new jobs', '5+ new jobs',
    'jobbenachrichtigung', 'job benachrichtigung',
    'you have 1 new invitation',
    'asta sitzung', 'vorlesung', 'tutorium', 'klausur',
    'spannende jobs für dich', 'ich denke diese jobs passen',
    'system migration',
    'one-time-passcode', 'one-time password', 'passcode',
    'verification code', 'bestätigungscode',
    'ihr zugangscode', 'dein zugangscode',
    'complete your application', 'finish your application',
    'bewerbung abschließen'
  ],

  // ── Known ATS/Platform Domains (used in Gmail query) ──
  ats_domains: [
    'smartrecruiters.com', 'softgarden.io', 'greenhouse.io',
    'recruitee.com', 'onlyfy.jobs', 'personio.de',
    'workday.com', 'lever.co', 'successfactors.com',
    'successfactors.eu', 'join.com', 'bamboohr.com',
    'icims.com', 'taleo.net', 'broadbean.net',
    'candidatecare.com', 'workwise.io'
  ]
};

// Detect trigger source
let runMode = 'manual_backfill';
let emailData = null;
try {
  const triggerData = $('Gmail Trigger').first().json;
  if (triggerData && triggerData.id) {
    runMode = 'email_trigger';
    emailData = triggerData;
  }
} catch(e) {}

console.log(`�� Mode: ${runMode}`);
return [{ json: { runMode, emailData, config: CONFIG, triggeredAt: new Date().toISOString() } }];

// ╔══════════════════════════════════════════════════════╗
// ║  MODULE 1: SHEET RESOLVER                            ║
// ║  Checks if sheet exists, routes to create or use.   ║
// ╚══════════════════════════════════════════════════════╝

const driveResult = $input.first().json;
const modeData = $('⚙️ CONFIG (Edit Here)').first().json;

let sheetId = null;
if (driveResult.files?.length > 0) {
  sheetId = driveResult.files[0].id;
  console.log(`✅ Found existing sheet: ${sheetId}`);
} else {
  console.log(`📋 No sheet found - will create new one`);
}

return [{ json: {
  sheetExists: !!sheetId,
  spreadsheetId: sheetId,
  runMode: modeData.runMode,
  emailData: modeData.emailData,
  config: modeData.config,
  triggeredAt: modeData.triggeredAt
} }];

// Extract tab sheet IDs from existing spreadsheet
const metadata = $input.first().json;
const prev = $('📋 Sheet Resolver').first().json;

let applicationsSheetId = null, dashboardSheetId = null, logSheetId = null;

for (const sheet of (metadata.sheets || [])) {
  const p = sheet.properties || {};
  if (p.title === 'Applications')      applicationsSheetId = String(p.sheetId);
  if (p.title === 'Dashboard')         dashboardSheetId    = String(p.sheetId);
  if (p.title === 'Classification Log') logSheetId         = String(p.sheetId);
}

console.log(`Tab IDs: Apps=${applicationsSheetId} Dash=${dashboardSheetId} Log=${logSheetId}`);

return [{ json: {
  spreadsheetId: prev.spreadsheetId,
  applicationsSheetId,
  dashboardSheetId,
  logSheetId,
  runMode: prev.runMode,
  emailData: prev.emailData,
  config: prev.config,
  isNewSheet: false
} }];

// Extract tab IDs from newly created spreadsheet
const created = $input.first().json;
const prev = $('📋 Sheet Resolver').first().json;
const sheets = created.sheets || [];

let applicationsSheetId = null, dashboardSheetId = null, logSheetId = null;
for (const s of sheets) {
  const p = s.properties || {};
  if (p.title === 'Applications')       applicationsSheetId = String(p.sheetId);
  if (p.title === 'Dashboard')          dashboardSheetId    = String(p.sheetId);
  if (p.title === 'Classification Log') logSheetId          = String(p.sheetId);
}
// Fallback to index order
if (!applicationsSheetId && sheets[0]) applicationsSheetId = String(sheets[0].properties.sheetId);
if (!dashboardSheetId    && sheets[1]) dashboardSheetId    = String(sheets[1].properties.sheetId);
if (!logSheetId          && sheets[2]) logSheetId          = String(sheets[2].properties.sheetId);

console.log(`New Tab IDs: Apps=${applicationsSheetId} Dash=${dashboardSheetId} Log=${logSheetId}`);

return [{ json: {
  spreadsheetId: created.spreadsheetId,
  applicationsSheetId,
  dashboardSheetId,
  logSheetId,
  runMode: prev.runMode,
  emailData: prev.emailData,
  config: prev.config,
  isNewSheet: true
} }];

// ╔══════════════════════════════════════════════════════╗
// ║  MODULE 2: SHEET SETUP                               ║
// ║  Initializes headers and formatting for new sheets.  ║
// ╚══════════════════════════════════════════════════════╝

const data = $input.first().json;

// If sheet already existed, skip setup entirely
if (!data.isNewSheet) {
  console.log('⏭️ Existing sheet - skipping setup');
  return [{ json: { ...data, setupSkipped: true } }];
}

// Build all setup requests
const appId  = parseInt(data.applicationsSheetId);
const dashId = parseInt(data.dashboardSheetId);
const logId  = parseInt(data.logSheetId);

const headerValues = [["Date Applied","Company Name","Job Title","Platform","Status","Email Subject","Email From","Last Updated","Notes","Thread ID","Processed At"]];
const logHeaderValues = [["Timestamp","Classification","Company Name","Job Title","Platform","Confidence","Status","Email Subject","From","Reasoning"]];

return [{ json: {
  ...data,
  setupRequired: true,
  headerValues,
  logHeaderValues,
  batchFormatRequest: { requests: [
    // Applications header formatting
    { repeatCell: { range: { sheetId: appId, startRowIndex: 0, endRowIndex: 1, startColumnIndex: 0, endColumnIndex: 11 },
      cell: { userEnteredFormat: { backgroundColor: { red: 0.15, green: 0.35, blue: 0.75 },
        textFormat: { bold: true, fontSize: 11, foregroundColor: { red: 1, green: 1, blue: 1 } },
        horizontalAlignment: 'CENTER', verticalAlignment: 'MIDDLE' }},
      fields: 'userEnteredFormat(backgroundColor,textFormat,horizontalAlignment,verticalAlignment)' }},
    { updateSheetProperties: { properties: { sheetId: appId, gridProperties: { frozenRowCount: 1 } }, fields: 'gridProperties.frozenRowCount' }},
    // Column widths
    { updateDimensionProperties: { range: { sheetId: appId, dimension: 'COLUMNS', startIndex: 0, endIndex: 1 }, properties: { pixelSize: 110 }, fields: 'pixelSize' }},
    { updateDimensionProperties: { range: { sheetId: appId, dimension: 'COLUMNS', startIndex: 1, endIndex: 2 }, properties: { pixelSize: 200 }, fields: 'pixelSize' }},
    { updateDimensionProperties: { range: { sheetId: appId, dimension: 'COLUMNS', startIndex: 2, endIndex: 3 }, properties: { pixelSize: 280 }, fields: 'pixelSize' }},
    { updateDimensionProperties: { range: { sheetId: appId, dimension: 'COLUMNS', startIndex: 3, endIndex: 4 }, properties: { pixelSize: 120 }, fields: 'pixelSize' }},
    { updateDimensionProperties: { range: { sheetId: appId, dimension: 'COLUMNS', startIndex: 4, endIndex: 5 }, properties: { pixelSize: 140 }, fields: 'pixelSize' }},
    { updateDimensionProperties: { range: { sheetId: appId, dimension: 'COLUMNS', startIndex: 5, endIndex: 6 }, properties: { pixelSize: 300 }, fields: 'pixelSize' }},
    { updateDimensionProperties: { range: { sheetId: appId, dimension: 'COLUMNS', startIndex: 6, endIndex: 7 }, properties: { pixelSize: 220 }, fields: 'pixelSize' }},
    { updateDimensionProperties: { range: { sheetId: appId, dimension: 'COLUMNS', startIndex: 7, endIndex: 8 }, properties: { pixelSize: 110 }, fields: 'pixelSize' }},
    { updateDimensionProperties: { range: { sheetId: appId, dimension: 'COLUMNS', startIndex: 8, endIndex: 9 }, properties: { pixelSize: 300 }, fields: 'pixelSize' }},
    { updateDimensionProperties: { range: { sheetId: appId, dimension: 'COLUMNS', startIndex: 9, endIndex: 10 }, properties: { pixelSize: 150 }, fields: 'pixelSize' }},
    { updateDimensionProperties: { range: { sheetId: appId, dimension: 'COLUMNS', startIndex: 10, endIndex: 11 }, properties: { pixelSize: 180 }, fields: 'pixelSize' }},
    // Status conditional formatting
    { addConditionalFormatRule: { rule: { ranges: [{ sheetId: appId, startRowIndex: 1, startColumnIndex: 4, endColumnIndex: 5 }], booleanRule: { condition: { type: 'TEXT_EQ', values: [{ userEnteredValue: 'Applied' }] }, format: { backgroundColor: { red: 0.85, green: 0.92, blue: 1.0 } } } }, index: 0 }},
    { addConditionalFormatRule: { rule: { ranges: [{ sheetId: appId, startRowIndex: 1, startColumnIndex: 4, endColumnIndex: 5 }], booleanRule: { condition: { type: 'TEXT_EQ', values: [{ userEnteredValue: 'Rejected' }] }, format: { backgroundColor: { red: 1.0, green: 0.8, blue: 0.8 } } } }, index: 1 }},
    { addConditionalFormatRule: { rule: { ranges: [{ sheetId: appId, startRowIndex: 1, startColumnIndex: 4, endColumnIndex: 5 }], booleanRule: { condition: { type: 'TEXT_EQ', values: [{ userEnteredValue: 'Positive Response' }] }, format: { backgroundColor: { red: 0.72, green: 0.95, blue: 0.72 } } } }, index: 2 }},
    { addConditionalFormatRule: { rule: { ranges: [{ sheetId: appId, startRowIndex: 1, startColumnIndex: 4, endColumnIndex: 5 }], booleanRule: { condition: { type: 'TEXT_EQ', values: [{ userEnteredValue: 'Interview' }] }, format: { backgroundColor: { red: 1.0, green: 0.95, blue: 0.6 } } } }, index: 3 }},
    { addConditionalFormatRule: { rule: { ranges: [{ sheetId: appId, startRowIndex: 1, startColumnIndex: 4, endColumnIndex: 5 }], booleanRule: { condition: { type: 'TEXT_EQ', values: [{ userEnteredValue: 'Offer' }] }, format: { backgroundColor: { red: 0.6, green: 1.0, blue: 0.6 } } } }, index: 4 }},
    // Dashboard header
    { repeatCell: { range: { sheetId: dashId, startRowIndex: 0, endRowIndex: 1, startColumnIndex: 0, endColumnIndex: 3 },
      cell: { userEnteredFormat: { backgroundColor: { red: 0.1, green: 0.3, blue: 0.6 },
        textFormat: { bold: true, fontSize: 14, foregroundColor: { red: 1, green: 1, blue: 1 } } } },
      fields: 'userEnteredFormat(backgroundColor,textFormat)' }},
    { updateSheetProperties: { properties: { sheetId: dashId, gridProperties: { frozenRowCount: 1 } }, fields: 'gridProperties.frozenRowCount' }},
    // Log header
    { repeatCell: { range: { sheetId: logId, startRowIndex: 0, endRowIndex: 1, startColumnIndex: 0, endColumnIndex: 10 },
      cell: { userEnteredFormat: { backgroundColor: { red: 0.2, green: 0.2, blue: 0.2 },
        textFormat: { bold: true, fontSize: 10, foregroundColor: { red: 1, green: 1, blue: 1 } } } },
      fields: 'userEnteredFormat(backgroundColor,textFormat)' }},
    { updateSheetProperties: { properties: { sheetId: logId, gridProperties: { frozenRowCount: 1 } }, fields: 'gridProperties.frozenRowCount' }}
  ]}
} }];

// Pass through sheet info after all setup steps complete
const d = $('🏗️ Sheet Setup Builder').first().json;
return [{ json: d }];

// ╔══════════════════════════════════════════════════════════╗
// ║  MODULE 3: GMAIL QUERY BUILDER (FIXED)                   ║
// ║  Single query instead of monthly chunks.                  ║
// ║  Uses staticData checkpoint for incremental fetching.    ║
// ║  FIX: Eliminates the 4x loop between Fetch↔Deduplicate  ║
// ╚══════════════════════════════════════════════════════════╝

const data = $input.first().json;
const config = data.config;

// Usar staticData para checkpoint persistente
const cache = $getWorkflowStaticData('global');

// Determinar la fecha de inicio de la búsqueda
// Primera ejecución: usa backfill_after del config
// Ejecuciones siguientes: usa el checkpoint guardado
let afterDate = config.backfill_after || '2025/10/01';

if (cache.lastCheckpointDate) {
  afterDate = cache.lastCheckpointDate;
  console.log(`📅 Incremental mode — fetching since checkpoint: ${afterDate}`);
} else {
  console.log(`📅 First run (backfill) — fetching since: ${afterDate}`);
}

const beforeDate = config.backfill_before || '2026/04/05';

// Exclusiones server-side en la query de Gmail
const queryExclusions = [
  'jobalerts-noreply@linkedin.com',
  'info@jobagent.stepstone.de',
  'jobalert@indeed.com',
  'alert@indeed.com',
  'noreply@indeed.com',
  'news@mail.xing.com'
].map(s => `-from:${s}`).join(' ');

// Keywords de búsqueda (idénticos al original)
const keywords = [
  'bewerbung', 'application', 'absage', 'rejection',
  'einladung', 'interview', 'eingangsbestätigung',
  'eingangsbestaetigung', 'angebot', 'offer',
  '"thank you for applying"', '"we received"',
  '"ihre bewerbung"', '"deine bewerbung"'
].join(' OR ');

// ═══════════════════════════════════════════════════════════
// KEY FIX: UNA SOLA query en vez de chunks mensuales.
// returnAll:true en el nodo Gmail maneja la paginación.
// Los chunks mensuales eran innecesarios y causaban el loop.
// ═══════════════════════════════════════════════════════════
const query = `(${keywords}) ${queryExclusions} after:${afterDate} before:${beforeDate}`;

console.log(`📧 Single query (no monthly chunks): ${query.substring(0, 130)}...`);

// Retornar UN solo item — Fetch Emails se ejecuta 1 vez, no 4+
return [{ json: {
  ...data,
  chunkLabel: 'single',
  gmailQuery: query
} }];

// ╔══════════════════════════════════════════════════════════╗
// ║  MODULE 4: EMAIL DEDUPLICATOR (FIXED)                    ║
// ║  Now saves checkpoint date after successful processing.  ║
// ║  Cache persists across runs via $getWorkflowStaticData.  ║
// ╚══════════════════════════════════════════════════════════╝

const allItems = $input.all();
const sheetInfo = $('🔀 Merge Sheet Info').first().json;

console.log(`📥 Total fetched: ${allItems.length}`);

// Deduplicate by Gmail message ID
const seen = new Map();
for (const item of allItems) {
  const email = item.json;
  const id = email.id || email.messageId;
  if (id && !seen.has(id)) seen.set(id, email);
}
const unique = Array.from(seen.values());
console.log(`🔄 After dedup: ${unique.length} unique emails`);

// Cache management
const cache = $getWorkflowStaticData('global');
if (!cache.processedEmailIds) cache.processedEmailIds = {};

// Clean entries older than 90 days
const cutoff = Date.now() - (90 * 24 * 60 * 60 * 1000);
let cleaned = 0;
for (const [id, ts] of Object.entries(cache.processedEmailIds)) {
  if (typeof ts === 'number' && ts < cutoff) { delete cache.processedEmailIds[id]; cleaned++; }
}
if (cleaned > 0) console.log(`🗑️ Cache: removed ${cleaned} expired entries`);
console.log(`📦 Cache: ${Object.keys(cache.processedEmailIds).length} entries`);

// Filter new emails
const newEmails = unique.filter(e => {
  const id = e.id || e.messageId;
  return id && !cache.processedEmailIds[id];
});

console.log(`🆕 New to process: ${newEmails.length} | Already cached: ${unique.length - newEmails.length}`);

// ═══════════════════════════════════════════════════════════
// KEY FIX: Guardar checkpoint para que la próxima ejecución
// solo busque emails desde esta fecha.
// Esto elimina la necesidad de re-fetchar todo el historial.
// ═══════════════════════════════════════════════════════════
const today = new Date();
const yyyy = today.getFullYear();
const mm = String(today.getMonth() + 1).padStart(2, '0');
const dd = String(today.getDate()).padStart(2, '0');
cache.lastCheckpointDate = `${yyyy}/${mm}/${dd}`;
console.log(`💾 Checkpoint saved: ${cache.lastCheckpointDate}`);

if (newEmails.length === 0) {
  return [{ json: {
    spreadsheetId: sheetInfo.spreadsheetId,
    logSheetId: String(sheetInfo.logSheetId || ''),
    config: sheetInfo.config,
    noEmails: true,
    reason: `All ${unique.length} emails already processed`
  } }];
}

return newEmails.map(email => ({ json: {
  spreadsheetId: sheetInfo.spreadsheetId,
  logSheetId: String(sheetInfo.logSheetId || ''),
  applicationsSheetId: String(sheetInfo.applicationsSheetId || ''),
  config: sheetInfo.config,
  email
} }));

// Handle single email from Gmail Trigger
const sheetInfo = $('🔀 Merge Sheet Info').first().json;
const email = sheetInfo.emailData;

if (!email) {
  return [{ json: {
    spreadsheetId: sheetInfo.spreadsheetId,
    logSheetId: String(sheetInfo.logSheetId || ''),
    applicationsSheetId: String(sheetInfo.applicationsSheetId || ''),
    config: sheetInfo.config,
    noEmails: true,
    reason: 'No email data from trigger'
  } }];
}

console.log(`📧 Processing single triggered email: ${email.id}`);
return [{ json: {
  spreadsheetId: sheetInfo.spreadsheetId,
  logSheetId: String(sheetInfo.logSheetId || ''),
  applicationsSheetId: String(sheetInfo.applicationsSheetId || ''),
  config: sheetInfo.config,
  email
} }];

// ╔══════════════════════════════════════════════════════════╗
// ║  MODULE 5: PRE-FILTER                                    ║
// ║  Fast rule-based filtering BEFORE spending Gemini tokens.║
// ║  Blocks: job alerts, newsletters, OTP codes, etc.        ║
// ╚══════════════════════════════════════════════════════════╝

const passed = [];
const filtered = [];
let stats = { total: 0, sender: 0, subject: 0, university: 0, self: 0, passed: 0 };

for (const item of $input.all()) {
  const d = item.json;
  if (!d.email || d.noEmails) continue;
  stats.total++;

  const email = d.email;
  const cfg = d.config || {};

  // ── Extract subject ────────────────────────────────────
  const subject = (
    email.subject ||
    email.headers?.subject ||
    email.payload?.headers?.find(h => h.name?.toLowerCase() === 'subject')?.value ||
    ''
  ).toLowerCase().trim();

  // ── Extract sender email ───────────────────────────────
  let fromEmail = '', fromRaw = '';
  if (typeof email.from === 'string') {
    fromRaw = email.from;
    const m = email.from.match(/<([^>]+)>/);
    fromEmail = (m ? m[1] : email.from).toLowerCase();
  } else if (email.from?.value?.[0]) {
    fromEmail = (email.from.value[0].address || '').toLowerCase();
    fromRaw = email.from.value[0].name
      ? `${email.from.value[0].name} <${fromEmail}>`
      : fromEmail;
  } else if (email.headers?.from) {
    fromRaw = email.headers.from;
    const m = email.headers.from.match(/<([^>]+)>/);
    fromEmail = (m ? m[1] : email.headers.from).toLowerCase();
  }

  // ── FILTER 1: Exact blocked senders ───────────────────
  if ((cfg.blocked_senders_exact || []).some(s => fromEmail === s.toLowerCase())) {
    stats.sender++;
    filtered.push({ reason: 'blocked_sender', from: fromEmail, subject: subject.substring(0,60) });
    continue;
  }

  // ── FILTER 2: Sender patterns ──────────────────────────
  if ((cfg.sender_block_patterns || []).some(p => fromEmail.includes(p.toLowerCase()))) {
    stats.sender++;
    filtered.push({ reason: 'sender_pattern', from: fromEmail, subject: subject.substring(0,60) });
    continue;
  }

  // ── FILTER 3: Self-sent ────────────────────────────────
  if ((cfg.user_email || '').toLowerCase() === fromEmail) {
    stats.self++;
    filtered.push({ reason: 'self_sent', from: fromEmail, subject: subject.substring(0,60) });
    continue;
  }

  // ── FILTER 4: Subject exclusions ──────────────────────
  const badSubject = (cfg.subject_always_exclude || []).find(kw => subject.includes(kw.toLowerCase()));
  if (badSubject) {
    stats.subject++;
    filtered.push({ reason: `subject:"${badSubject}"`, from: fromEmail, subject: subject.substring(0,60) });
    continue;
  }

  // ── FILTER 5: University (unless job keyword present) ──
  if ((cfg.university_patterns || []).some(p => fromEmail.includes(p.toLowerCase()))) {
    const jobKw = ['bewerbung','application','absage','rejection','eingangsbestätigung','thank you for applying'];
    if (!jobKw.some(k => subject.includes(k))) {
      stats.university++;
      filtered.push({ reason: 'university', from: fromEmail, subject: subject.substring(0,60) });
      continue;
    }
  }

  stats.passed++;
  passed.push({ json: { ...d, _fromEmail: fromEmail, _fromRaw: fromRaw } });
}

console.log(`📊 Pre-filter: ${stats.passed}/${stats.total} passed`);
console.log(`❌ Filtered: Sender=${stats.sender} Subject=${stats.subject} Uni=${stats.university} Self=${stats.self}`);
if (filtered.length > 0) {
  console.log('🔍 Filtered list (first 15):');
  filtered.slice(0,15).forEach((e,i) => console.log(`  ${i+1}. [${e.reason}] "${e.subject}" | ${e.from}`));
}

if (passed.length === 0) {
  const f = $input.first()?.json || {};
  return [{ json: {
    spreadsheetId: f.spreadsheetId, logSheetId: f.logSheetId,
    config: f.config, noEmails: true,
    reason: `All ${stats.total} filtered (sender:${stats.sender} subject:${stats.subject})`
  } }];
}
return passed;

// ╔══════════════════════════════════════════════════════════╗
// ║  MODULE 6: GEMINI BATCH BUILDER                          ║
// ║  Groups emails into batches, extracts body text,         ║
// ║  builds optimized prompts for the Gemini API.            ║
// ╚══════════════════════════════════════════════════════════╝

const allItems = $input.all();
const firstValid = allItems.find(i => !i.json.noEmails);

if (!firstValid) {
  return [{ json: { noBatches: true } }];
}

const cfg = firstValid.json.config || {};
const BATCH_SIZE = cfg.gemini_batch_size || 10;
const MODEL = cfg.gemini_model || 'gemini-3.1-flash-lite-preview';
const DELAY = cfg.batch_delay_ms || 2000;
const THINKING = cfg.thinking_level || 'minimal';
const MAX_BODY = 800;

function extractBody(email) {
  if (email.textPlain) return email.textPlain.substring(0, MAX_BODY);
  if (email.text)      return email.text.substring(0, MAX_BODY);

  const findInParts = (parts) => {
    if (!parts) return '';
    for (const p of parts) {
      if (p.mimeType === 'text/plain' && p.body?.data) {
        try { return Buffer.from(p.body.data, 'base64').toString('utf-8').substring(0, MAX_BODY); } catch(e) {}
        try { return Buffer.from(p.body.data, 'base64url').toString('utf-8').substring(0, MAX_BODY); } catch(e) {}
      }
      const nested = findInParts(p.parts);
      if (nested) return nested;
    }
    return '';
  };

  const fromParts = findInParts(email.payload?.parts);
  if (fromParts) return fromParts;

  if (email.payload?.body?.data) {
    try { return Buffer.from(email.payload.body.data, 'base64').toString('utf-8').substring(0, MAX_BODY); } catch(e) {}
  }

  return (email.snippet || '').substring(0, MAX_BODY);
}

function extractMeta(item) {
  const email = item.json.email || {};

  const emailId  = email.id || email.messageId || '';
  const threadId = email.threadId || email.thread_id || '';

  const subject = (
    email.subject ||
    email.headers?.subject ||
    email.payload?.headers?.find(h => h.name === 'Subject')?.value ||
    ''
  ).trim();

  let from = item.json._fromRaw || '';
  if (!from) {
    if (typeof email.from === 'string') from = email.from;
    else if (email.from?.value?.[0]?.address) {
      const v = email.from.value[0];
      from = v.name ? `${v.name} <${v.address}>` : v.address;
    } else if (email.headers?.from) from = email.headers.from;
  }

  const rawDate = email.date || email.internalDate || email.headers?.date || '';
  let parsedDate = new Date().toISOString().split('T')[0];
  try {
    if (/^\d{13}$/.test(String(rawDate))) parsedDate = new Date(parseInt(rawDate)).toISOString().split('T')[0];
    else if (/^\d{10}$/.test(String(rawDate))) parsedDate = new Date(parseInt(rawDate) * 1000).toISOString().split('T')[0];
    else if (rawDate) { const d = new Date(rawDate); if (!isNaN(d)) parsedDate = d.toISOString().split('T')[0]; }
  } catch(e) {}

  const body = extractBody(email);

  return {
    emailId, threadId, subject, from, parsedDate, body,
    spreadsheetId: item.json.spreadsheetId,
    logSheetId: item.json.logSheetId,
    applicationsSheetId: item.json.applicationsSheetId,
    config: item.json.config
  };
}

// Build batches
const batches = [];
for (let i = 0; i < allItems.length; i += BATCH_SIZE) {
  batches.push(allItems.slice(i, i + BATCH_SIZE));
}
console.log(`📦 ${allItems.length} emails → ${batches.length} batches (max ${BATCH_SIZE}) | Model: ${MODEL} | Thinking: ${THINKING}`);

return batches.map((batchItems, batchIdx) => {
  const metas = batchItems.map((item, idx) => ({ index: idx, ...extractMeta(item) }));

  const emailsText = metas.map((m, i) =>
    `=== EMAIL ${i+1} ===\nSubject: ${m.subject}\nFrom: ${m.from}\nDate: ${m.parsedDate}\nBody:\n${m.body || '(empty)'}`
  ).join('\n\n---\n\n');

  const prompt = `You are a job application email classifier for a German job seeker.
Classify each email into exactly one of 4 types. Return ONLY valid JSON.

TYPES:
1. "application_confirmation" - Company confirmed receiving YOUR job application
   → Eingangsbestätigung, Bewerbung erhalten, Vielen Dank für Ihre/deine Bewerbung,
     we received your application, application confirmed, Your Application - [Title],
     Deine Bewerbung bei [Company], wir haben Ihre Unterlagen erhalten

2. "rejection" - Application was declined
   → leider absagen, leider müssen wir, andere Kandidaten, unfortunately,
     cannot offer, unable to proceed, nicht berücksichtigen, we regret,
     have decided to move forward with other candidates

3. "positive_response" - Interview invite, assessment, or offer
   → einladen, Vorstellungsgespräch, Kennenlerngespräch, assessment,
     we would like to invite, next steps, please schedule, können wir einen Termin

4. "not_job_related" - Anything else
   → job alerts, newsletters, OTP codes, account confirmations, marketing

EXTRACTION:
- company_name: The HIRING company, NOT the ATS/platform
  * "Bosch Group <notifications@smartrecruiters.com>" → "Robert Bosch GmbH"
  * "HR <e113-jobs@m.personio.de>" → extract from body or use "E113"
  * "anna@dekra.com" → "DEKRA"
  * NEVER use: SmartRecruiters, Personio, Workday, Lever, Greenhouse, Workwise, Onlyfy

- job_title: Exact role title. "Not Specified" if unclear.

- platform:
  smartrecruiters.com→SmartRecruiters, m.personio.de→Personio,
  workday.com→Workday, lever.co→Lever, greenhouse.io→Greenhouse,
  successfactors.com/eu→SAP SuccessFactors, softgarden.io→Softgarden,
  onlyfy.jobs→Onlyfy, workwise.io→Workwise, recruitee.com→Recruitee,
  bamboohr.com→BambooHR, company own domain→Direct, unknown→Direct

- confidence: 0.9+=very clear, 0.7-0.89=likely, 0.55-0.69=uncertain, <0.55=not_job_related

EMAILS:
${emailsText}

JSON response only:
{"results":[{"email_index":1,"classification":"application_confirmation","company_name":"Company","job_title":"Title or Not Specified","platform":"Platform","confidence":0.95,"reasoning":"Brief reason"}]}`;

  // Build generationConfig with thinking support for Gemini 3 models
  const isGemini3 = MODEL.includes('gemini-3');
  const generationConfig = {
    temperature: 0.05,
    maxOutputTokens: Math.max(1500, batchItems.length * 300),
    responseMimeType: 'application/json'
  };
  if (isGemini3) {
    generationConfig.thinkingConfig = { thinkingBudget: THINKING === 'minimal' ? 0 : undefined, thinking_level: THINKING };
  }

  return { json: {
    batchIndex: batchIdx,
    totalBatches: batches.length,
    emailCount: batchItems.length,
    emailMetas: metas,
    model: MODEL,
    delayMs: batchIdx > 0 ? DELAY : 0,
    geminiRequest: {
      contents: [{ parts: [{ text: prompt }] }],
      generationConfig,
      safetySettings: [
        { category: 'HARM_CATEGORY_HARASSMENT',        threshold: 'BLOCK_NONE' },
        { category: 'HARM_CATEGORY_HATE_SPEECH',        threshold: 'BLOCK_NONE' },
        { category: 'HARM_CATEGORY_SEXUALLY_EXPLICIT',  threshold: 'BLOCK_NONE' },
        { category: 'HARM_CATEGORY_DANGEROUS_CONTENT',  threshold: 'BLOCK_NONE' }
      ]
    }
  } };
});

const input = $input.first().json;
if (input.delayMs > 0) {
  console.log(`⏳ Waiting ${input.delayMs}ms before batch ${input.batchIndex + 1}/${input.totalBatches}`);
  await new Promise(r => setTimeout(r, input.delayMs));
}
console.log(`📤 Sending batch ${input.batchIndex + 1}/${input.totalBatches} (${input.emailCount} emails) to Gemini`);
return [$input.first()];

// ╔══════════════════════════════════════════════════════════╗
// ║  MODULE 7: RESULT EXPANDER                               ║
// ║  Parses Gemini JSON response, maps results back to       ║
// ║  original emails, marks processed in cache.              ║
// ╚══════════════════════════════════════════════════════════╝

const batchMeta = $('⏱️ Rate Limit Delay').first().json;
const resp      = $input.first().json;

const cache = $getWorkflowStaticData('global');
if (!cache.processedEmailIds) cache.processedEmailIds = {};

const markProcessed = (emailId) => {
  if (emailId) cache.processedEmailIds[emailId] = Date.now();
};

const makeErrorResult = (meta, errMsg) => {
  markProcessed(meta.emailId);
  return { json: {
    spreadsheetId:       meta.spreadsheetId,
    logSheetId:          String(meta.logSheetId || ''),
    applicationsSheetId: String(meta.applicationsSheetId || ''),
    config:              meta.config,
    is_job_related:      false,
    classification:      'api_error',
    company_name:        'Error',
    job_title:           'Error',
    platform:            'Unknown',
    status:              '',
    confidence:          0,
    error:               errMsg.substring(0, 300),
    reasoning:           errMsg.substring(0, 200),
    email_subject:       meta.subject,
    email_from:          meta.from,
    email_date:          meta.parsedDate,
    emailId:             meta.emailId,
    threadId:            meta.threadId
  } };
};

if (!batchMeta?.emailMetas) {
  console.error('❌ No batch metadata found');
  return [{ json: { is_job_related: false, classification: 'parse_error', company_name: 'Error', job_title: 'Error', platform: 'Unknown', status: '', confidence: 0 } }];
}

// Handle API error response
if (resp.error) {
  const msg = `Gemini Error ${resp.error.code}: ${resp.error.message || 'Unknown'}`;
  console.error(`❌ ${msg}`);
  return batchMeta.emailMetas.map(m => makeErrorResult(m, msg));
}

// Extract text from response (skip thinking parts)
let content = '';
for (const part of (resp.candidates?.[0]?.content?.parts || [])) {
  if (part.thought === true) continue;
  if (part.text) { content = part.text; break; }
}
if (!content) content = resp.candidates?.[0]?.content?.parts?.[0]?.text || '';

if (!content) {
  console.error('❌ Empty Gemini response');
  return batchMeta.emailMetas.map(m => makeErrorResult(m, 'Empty response from Gemini'));
}

// Clean and parse JSON
content = content.replace(/```json\s*/g, '').replace(/```\s*/g, '').trim();
const fb = content.indexOf('{'), lb = content.lastIndexOf('}');
if (fb === -1 || lb === -1) {
  const msg = `No JSON in response: ${content.substring(0, 200)}`;
  return batchMeta.emailMetas.map(m => makeErrorResult(m, msg));
}

let parsed;
try {
  parsed = JSON.parse(content.substring(fb, lb + 1));
} catch(e) {
  try {
    const fixed = content.substring(fb, lb + 1).replace(/,\s*([}\]])/g, '$1');
    parsed = JSON.parse(fixed);
  } catch(e2) {
    const msg = `JSON parse failed: ${e.message}`;
    return batchMeta.emailMetas.map(m => makeErrorResult(m, msg));
  }
}

const results = parsed.results || [];
console.log(`✅ Batch ${batchMeta.batchIndex + 1}/${batchMeta.totalBatches}: ${results.length} results for ${batchMeta.emailMetas.length} emails`);

// Constants
const STATUS_MAP = {
  application_confirmation: 'Applied',
  rejection:                'Rejected',
  positive_response:        'Positive Response',
  not_job_related:          ''
};
const JOB_CLASSES = ['application_confirmation', 'rejection', 'positive_response'];

const PLATFORM_DOMAINS = ['smartrecruiters','softgarden','greenhouse','recruitee',
  'onlyfy','personio','workday','lever','successfactors','bamboohr','icims',
  'taleo','broadbean','workwise','hokify','join.com','stepstone','linkedin',
  'indeed','xing','glassdoor','monster'];

function detectPlatform(fromStr, aiPlatform) {
  const VALID_PLATFORMS = ['SmartRecruiters','Onlyfy','Personio','Workday','Lever',
    'Greenhouse','SAP SuccessFactors','BambooHR','Recruitee','Softgarden','iCIMS',
    'Oracle Taleo','Broadbean','LinkedIn','StepStone','Indeed','Xing','JOIN','Workwise','Direct'];
  if (aiPlatform && VALID_PLATFORMS.includes(aiPlatform)) return aiPlatform;
  const f = (fromStr || '').toLowerCase();
  const MAP = [
    ['smartrecruiters','SmartRecruiters'],['onlyfy','Onlyfy'],['personio','Personio'],
    ['workday','Workday'],['lever.co','Lever'],['greenhouse','Greenhouse'],
    ['successfactors','SAP SuccessFactors'],['bamboohr','BambooHR'],['recruitee','Recruitee'],
    ['softgarden','Softgarden'],['icims','iCIMS'],['taleo','Oracle Taleo'],
    ['broadbean','Broadbean'],['workwise','Workwise'],['linkedin','LinkedIn'],
    ['stepstone','StepStone'],['indeed','Indeed'],['xing.com','Xing'],['join.com','JOIN']
  ];
  for (const [k,v] of MAP) { if (f.includes(k)) return v; }
  return 'Direct';
}

function cleanCompany(name) {
  if (!name) return null;
  const n = name.trim();
  if (PLATFORM_DOMAINS.some(p => n.toLowerCase().includes(p))) return null;
  if (['unknown','not specified','n/a','none',''].includes(n.toLowerCase())) return null;
  return n;
}

function domainToCompany(fromStr) {
  const m = (fromStr || '').match(/@([\w.-]+)/);
  if (!m) return null;
  const domain = m[1].toLowerCase();
  if (PLATFORM_DOMAINS.some(p => domain.includes(p))) return null;
  const GENERIC = ['gmail.com','yahoo.com','hotmail.com','outlook.com','web.de','gmx.de','gmx.net'];
  if (GENERIC.includes(domain)) return null;
  const name = domain
    .replace(/\.(com|de|io|net|org|eu|jobs|at|ch|fr|nl|co\.uk)$/, '')
    .replace(/^(mail|email|reply|noreply|no-reply|notification|notifications|info|career|careers|recruiting|hr|jobs|talent|bewerbung|support|team|hello|pimsprod|donotreply)\./i, '')
    .replace(/[-_.]/g, ' ').trim();
  if (name.length < 2) return null;
  return name.split(' ').map(w => w.charAt(0).toUpperCase() + w.slice(1)).join(' ');
}

// Build result map (Gemini uses 1-based index)
const resultMap = {};
for (const r of results) {
  const idx = (r.email_index || 1) - 1;
  if (idx >= 0 && idx < batchMeta.emailMetas.length) resultMap[idx] = r;
}
// Sequential fallback if indices are all wrong
if (Object.keys(resultMap).length === 0 && results.length > 0) {
  results.forEach((r,i) => { if (i < batchMeta.emailMetas.length) resultMap[i] = r; });
}

return batchMeta.emailMetas.map((meta, idx) => {
  const r = resultMap[idx];
  if (!r) {
    console.warn(`⚠️ No result for email ${idx+1}: "${(meta.subject||'').substring(0,50)}"`);
    markProcessed(meta.emailId);
    return makeErrorResult(meta, 'Gemini returned no result for this email');
  }

  const cls        = JOB_CLASSES.includes(r.classification) ? r.classification : 'not_job_related';
  const isJob      = JOB_CLASSES.includes(cls);
  const status     = STATUS_MAP[cls] || '';
  const platform   = detectPlatform(meta.from, r.platform);
  const confidence = parseFloat(r.confidence) || 0;
  const company    = cleanCompany(r.company_name) || domainToCompany(meta.from) || 'Unknown';

  markProcessed(meta.emailId);

  const icon = { application_confirmation:'📝', rejection:'❌', positive_response:'🎉', not_job_related:'⬛' }[cls] || '❓';
  console.log(`  ${icon} [${idx+1}] ${cls} (${confidence.toFixed(2)}) | ${company} | "${(meta.subject||'').substring(0,40)}"`);

  return { json: {
    spreadsheetId:       meta.spreadsheetId,
    logSheetId:          String(meta.logSheetId || ''),
    applicationsSheetId: String(meta.applicationsSheetId || ''),
    config:              meta.config,
    is_job_related:      isJob,
    classification:      cls,
    company_name:        company,
    job_title:           (r.job_title || 'Not Specified').trim(),
    platform,
    status,
    confidence,
    reasoning:           (r.reasoning || '').substring(0, 200),
    email_subject:       meta.subject,
    email_from:          meta.from,
    email_date:          meta.parsedDate,
    emailId:             meta.emailId,
    threadId:            meta.threadId
  } };
});

// ╔══════════════════════════════════════════════════════════╗
// ║  MODULE 8: CLASSIFICATION FILTER                         ║
// ║  Routes emails: valid job emails → sheet                 ║
// ║                 non-job / errors → log only              ║
// ╚══════════════════════════════════════════════════════════╝

const d = $input.first().json;

// Type-safe checks
const isJobRelated = d.is_job_related === true;
const confidence   = parseFloat(d.confidence) || 0;
const status       = (d.status || '').trim();
const minConf      = parseFloat(d.config?.min_confidence) || 0.55;

const isValid = isJobRelated && confidence >= minConf && status !== '';

console.log(`🔍 Filter: ${d.company_name} | job=${isJobRelated} conf=${confidence.toFixed(2)} status="${status}" → ${isValid ? 'VALID ✅' : 'SKIP ❌'}`);

return [{ json: { ...d, _isValidJob: isValid } }];

// ╔══════════════════════════════════════════════════════════╗
// ║  MODULE 9: CLASSIFICATION LOGGER                         ║
// ║  Logs EVERY email classification result (pass or fail)   ║
// ║  to the Classification Log sheet for debugging.          ║
// ╚══════════════════════════════════════════════════════════╝

const d = $input.first().json;
return [{ json: {
  spreadsheetId: d.spreadsheetId,
  logSheetId:    d.logSheetId,
  config:        d.config,
  _passedFilter: d._isValidJob || false,
  // Pass through all fields for downstream nodes
  ...d,
  // Log row data
  _logRow: {
    Timestamp:       new Date().toISOString(),
    Classification:  d.classification || 'unknown',
    'Company Name':  (d.company_name || 'Unknown').substring(0, 100),
    'Job Title':     (d.job_title || 'Not Specified').substring(0, 150),
    Platform:        d.platform || 'Unknown',
    Confidence:      d.confidence || 0,
    Status:          d.status || '',
    'Email Subject': (d.email_subject || '').substring(0, 150),
    From:            (d.email_from || '').substring(0, 100),
    Reasoning:       (d.reasoning || d.error || '').substring(0, 200)
  }
} }];

// ╔══════════════════════════════════════════════════════════╗
// ║  MODULE 10: DEDUPLICATION ENGINE                         ║
// ║  Compares email against existing sheet rows.             ║
// ║  Uses Thread ID (primary) + fuzzy company match.         ║
// ║  Status priority: Applied→Positive→Interview→Rejected    ║
// ║  Rejected can overwrite anything except Offer.           ║
// ╚══════════════════════════════════════════════════════════╝

const sheetRows = $('📖 Read Applications Sheet').all()
  .filter(i => i.json?.['Company Name'] && Object.keys(i.json).length > 1);

const emailData      = $input.first().json;
const spreadsheetId  = emailData.spreadsheetId || '';
const today          = emailData.email_date || new Date().toISOString().split('T')[0];
const threadId       = emailData.threadId || '';
const newStatus      = emailData.status || '';

console.log(`🔍 Dedup: "${emailData.company_name}" | "${emailData.job_title}" | ${newStatus}`);
console.log(`   Sheet rows: ${sheetRows.length} | Thread: ${threadId || 'none'}`);

// Always include spreadsheetId in all returns
const makeSkip = (reason) => [{ json: {
  action: 'skip',
  spreadsheetId,
  tabName: 'Applications',
  reason
} }];

if (!newStatus)      return makeSkip('No status value');
if (!spreadsheetId)  return makeSkip('No spreadsheetId');

// ── Normalizers ────────────────────────────────────────────
function normC(s) {
  return (s||'').toLowerCase()
    .replace(/\b(gmbh|ag|inc|ltd|co\.|corp|se|kg|group|gruppe|holding|services|solutions|technologies|tech|software|germany|deutschland|europe)\b/gi, '')
    .replace(/[^\wäöüß\s]/gi, '').replace(/\s+/g, ' ').trim();
}
function normT(s) {
  return (s||'').toLowerCase()
    .replace(/\(m\/w\/d\)|\(w\/m\/d\)|\(f\/m\/d\)|\(all genders\)|\(m\/f\/d\)|\(\*\)/gi, '')
    .replace(/[^\wäöüß\s]/gi, '').replace(/\s+/g, ' ').trim();
}
function companySim(a, b) {
  const na = normC(a), nb = normC(b);
  if (!na || !nb) return 0;
  if (na === nb) return 1.0;
  if (na.includes(nb) || nb.includes(na)) return 0.9;
  const wa = na.split(' ').filter(w => w.length > 2);
  const wb = nb.split(' ').filter(w => w.length > 2);
  if (!wa.length || !wb.length) return 0;
  return wa.filter(w => wb.some(x => x===w || x.includes(w) || w.includes(x))).length / Math.max(wa.length, wb.length);
}
function titleSim(a, b) {
  const na = normT(a), nb = normT(b);
  if (!na || !nb) return 0;
  if (na === nb) return 1.0;
  if (na.includes(nb) || nb.includes(na)) return 0.85;
  const wa = na.split(' ').filter(w => w.length > 3);
  const wb = nb.split(' ').filter(w => w.length > 3);
  if (!wa.length || !wb.length) return 0;
  return wa.filter(w => wb.includes(w)).length / Math.max(wa.length, wb.length);
}

// Status priority: higher = more final
// Rejected=99 so it can overwrite Applied/Positive/Interview but not Offer
const PRIORITY = { 'Applied':1, 'Positive Response':2, 'Interview':3, 'Offer':100, 'Rejected':99 };

// ── Step 1: Thread ID Match ────────────────────────────────
let bestMatch = null;
if (threadId) {
  for (const rowItem of sheetRows) {
    const row = rowItem.json;
    if ((row['Thread ID'] || '') !== threadId) continue;
    // Validate: titles shouldn't be completely different
    const et = normT(row['Job Title'] || '');
    const nt = normT(emailData.job_title || '');
    const bothSpecific = et && nt && et !== 'not specified' && nt !== 'not specified';
    if (bothSpecific && titleSim(et, nt) < 0.25) {
      console.log(`   ⚠️ Thread match rejected (title mismatch): "${row['Job Title']}" vs "${emailData.job_title}"`);
      continue;
    }
    bestMatch = row;
    console.log(`   🔗 Thread match: ${row['Company Name']} | ${row['Status']}`);
    break;
  }
}

// ── Step 2: Fuzzy Company+Title Match ─────────────────────
if (!bestMatch) {
  let bestScore = 0;
  for (const rowItem of sheetRows) {
    const row = rowItem.json;
    const cs = companySim(emailData.company_name, row['Company Name'] || '');
    if (cs < 0.5) continue;
    const nt = emailData.job_title, et = row['Job Title'] || '';
    let score = cs;
    if (nt && nt !== 'Not Specified' && et && et !== 'Not Specified') {
      const ts = titleSim(nt, et);
      score = (ts < 0.2 && cs < 0.95) ? 0 : (cs * 0.4 + ts * 0.6);
    } else {
      score = cs * 0.75;
    }
    if (score > bestScore && score >= 0.4) { bestScore = score; bestMatch = row; }
  }
  if (bestMatch) console.log(`   🔍 Fuzzy match: ${bestMatch['Company Name']} (score: ${bestScore.toFixed(2)})`);
}

// ── Step 3: Decide ─────────────────────────────────────────
if (bestMatch) {
  const curStatus = bestMatch['Status'] || 'Applied';
  if (curStatus === newStatus) {
    console.log(`   ⏭️ Skip: Already "${curStatus}"`);
    return makeSkip(`Already ${curStatus}`);
  }

  const cp = PRIORITY[curStatus] || 0;
  const np = PRIORITY[newStatus] || 0;
  // Upgrade if: new status has higher priority, OR it's a rejection (can overwrite most things)
  const shouldUpgrade = (np > cp) || (newStatus === 'Rejected' && curStatus !== 'Offer');

  if (shouldUpgrade) {
    const updatedTitle = (bestMatch['Job Title'] === 'Not Specified' && emailData.job_title !== 'Not Specified')
      ? emailData.job_title
      : bestMatch['Job Title'];
    console.log(`   ⬆️ Upgrade: "${curStatus}" → "${newStatus}"`);
    return [{ json: {
      action:          'update',
      spreadsheetId,
      tabName:         'Applications',
      'Company Name':  bestMatch['Company Name'],
      'Job Title':     updatedTitle,
      'Status':        newStatus,
      'Last Updated':  today,
      '_matchThreadId': bestMatch['Thread ID'] || '',
      'Processed At':  new Date().toISOString(),
      'Notes':         `${curStatus} → ${newStatus} | ${(emailData.email_subject||'').substring(0,100)}`
    } }];
  }

  console.log(`   🛡️ Protected: "${curStatus}" > "${newStatus}"`);
  return makeSkip(`Status protected: ${curStatus} supersedes ${newStatus}`);
}

// ── New Entry ──────────────────────────────────────────────
console.log(`   ✨ New application: ${emailData.company_name}`);
return [{ json: {
  action:          'add',
  spreadsheetId,
  tabName:         'Applications',
  'Date Applied':  today,
  'Company Name':  emailData.company_name,
  'Job Title':     emailData.job_title,
  'Platform':      emailData.platform,
  'Status':        newStatus,
  'Email Subject': (emailData.email_subject || '').substring(0, 150),
  'Email From':    emailData.email_from,
  'Last Updated':  today,
  'Notes':         (emailData.reasoning || '').substring(0, 150),
  'Thread ID':     threadId,
  'Processed At':  new Date().toISOString()
} }];

// ╔══════════════════════════════════════════════════════════╗
// ║  MODULE 11: TELEGRAM NOTIFIER                            ║
// ║  Sends notifications when enabled in config.             ║
// ║  Set telegram_enabled: true in CONFIG node to activate.  ║
// ╚══════════════════════════════════════════════════════════╝

const d = $input.first().json;
const cfg = d.config || {};

if (cfg.telegram_enabled !== true) {
  return [$input.first()]; // Pass through silently
}

const token  = cfg.telegram_bot_token || '';
const chatId = cfg.telegram_chat_id || '';
if (!token || !chatId || token === '' || chatId === '') {
  console.log('⚠️ Telegram enabled but credentials missing');
  return [$input.first()];
}

const EMOJI = { Applied:'📝', Rejected:'❌', 'Positive Response':'🎉', Interview:'🤝', Offer:'🏆' };
const isNew = d._isNewEntry !== false;
const emoji = EMOJI[d['Status']] || '📌';

const text = isNew
  ? [
      `${emoji} *New Application Tracked*`,
      `🏢 *Company:* ${d['Company Name']}`,
      `💼 *Role:* ${d['Job Title']}`,
      `🔗 *Platform:* ${d['Platform']}`,
      `📅 *Date:* ${d['Date Applied']}`,
      `📧 ${(d['Email Subject'] || '').substring(0, 80)}`
    ].join('\n')
  : [
      `${emoji} *Status Update*`,
      `🏢 *Company:* ${d['Company Name']}`,
      `💼 *Role:* ${d['Job Title']}`,
      `📋 *Update:* ${(d['Notes'] || '').substring(0, 120)}`
    ].join('\n');

return [{ json: {
  ...d,
  _tg_token:      token,
  _tg_chat_id:    String(chatId),
  _tg_text:       text,
  _tg_parse_mode: 'Markdown'
} }];
